import{_ as a,o as t,c as o,a3 as r}from"./chunks/framework.CjquFG0V.js";const c=JSON.parse('{"title":"204. Overtime Royal Children S Hospital","description":"","frontmatter":{"title":"204. Overtime Royal Children S Hospital","eba":"Mental Health Services 2024-2028","topics":["hours","overtime","wages","preliminary"]},"headers":[],"relativePath":"ebas/mental-health/management-admin/hours-of-work/204-overtime-royal-children-s-hospital.md","filePath":"ebas/mental-health/management-admin/hours-of-work/204-overtime-royal-children-s-hospital.md"}'),i={name:"ebas/mental-health/management-admin/hours-of-work/204-overtime-royal-children-s-hospital.md"};function s(l,e,n,h,m,d){return t(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="_204-overtime-royal-children-s-hospital" tabindex="-1">204. Overtime Royal Children S Hospital <a class="header-anchor" href="#_204-overtime-royal-children-s-hospital" aria-label="Permalink to &quot;204. Overtime Royal Children S Hospital&quot;">​</a></h1><p>This clause only applies to Management and Administrative Officers at Royal Children’s Hospital classified under Part 2 of <a href="/eba/ebas/mental-health/schedules/06-support-services-employee-classifications.html">Schedule 6</a> of this Agreement.</p><p><strong>204.1</strong> Employees in receipt of an annualised salary, or classified in Grades 3 to 8 of the classification structure in Part 2 of <a href="/eba/ebas/mental-health/schedules/06-support-services-employee-classifications.html">Schedule 6</a> of this Agreement are not entitled to payment of overtime under <a href="/eba/ebas/mental-health/management-admin/hours-of-work/203-overtime.html">clause 203</a> (Overtime), other than for:</p><p><strong>(a)</strong> periods of recall to duty</p><p><strong>(b)</strong> periods when the Employee is directed to work overtime on weekends; and/or</p><p><strong>(c)</strong> periods when the Employee is directed to work overtime on public holidays.</p><p><strong>204.2</strong> Such Employees will be compensated for reasonable additional hours through flexibility in hours worked or time off in lieu of payment for overtime, in accordance with <a href="/eba/ebas/mental-health/management-admin/hours-of-work/205-overtime-in-lieu.html">clause 205</a> (Overtime in Lieu).</p><p>Plain language terms: OT, extra hours, time and a half, double time, additional hours.</p>',8)])])}const f=a(i,[["render",s]]);export{c as __pageData,f as default};
